def get_user(user_id: str) -> dict:
    user = db.find(user_id)
    if user is None:
        return {
            "error": "USER_NOT_FOUND",
            "message": f"No user with id={user_id!r}. Check the ID or use list_users first."
        }
    return {"id": user.id, "name": user.name, "email": user.email}
